'use strict';
// Extract the loadable memory image of an ELF64 (little-endian) binary.
// For every PT_LOAD segment, emit each 4-byte little-endian word keyed by its
// virtual address. Output: JSON object { "<vaddr>": <int32>, ... }.

const fs = require('fs');

const path = process.argv[2];
if (!path) {
  process.stderr.write('usage: node extract.js <elf-file>\n');
  process.exit(1);
}

const buf = fs.readFileSync(path);

// ELF identification
if (buf.length < 64 ||
    buf[0] !== 0x7f || buf[1] !== 0x45 || buf[2] !== 0x4c || buf[3] !== 0x46) {
  process.stderr.write('not an ELF file\n');
  process.exit(1);
}

const ei_class = buf[4]; // 1 = 32-bit, 2 = 64-bit
const ei_data = buf[5];  // 1 = little-endian, 2 = big-endian
const le = ei_data !== 2;

function u16(o) { return le ? buf.readUInt16LE(o) : buf.readUInt16BE(o); }
function u32(o) { return le ? buf.readUInt32LE(o) : buf.readUInt32BE(o); }
function u64(o) {
  return le ? Number(buf.readBigUInt64LE(o)) : Number(buf.readBigUInt64BE(o));
}

const out = {};
const PT_LOAD = 1;

if (ei_class === 2) {
  // ELF64
  const e_phoff = u64(32);
  const e_phentsize = u16(54);
  const e_phnum = u16(56);
  for (let i = 0; i < e_phnum; i++) {
    const o = e_phoff + i * e_phentsize;
    const p_type = u32(o);
    if (p_type !== PT_LOAD) continue;
    const p_offset = u64(o + 8);
    const p_vaddr = u64(o + 16);
    const p_filesz = u64(o + 32);
    for (let j = 0; j + 4 <= p_filesz; j += 4) {
      const fileOff = p_offset + j;
      if (fileOff + 4 > buf.length) break;
      const val = le ? buf.readUInt32LE(fileOff) : buf.readUInt32BE(fileOff);
      out[p_vaddr + j] = val;
    }
  }
} else {
  // ELF32
  const e_phoff = u32(28);
  const e_phentsize = u16(42);
  const e_phnum = u16(44);
  for (let i = 0; i < e_phnum; i++) {
    const o = e_phoff + i * e_phentsize;
    const p_type = u32(o);
    if (p_type !== PT_LOAD) continue;
    const p_offset = u32(o + 4);
    const p_vaddr = u32(o + 8);
    const p_filesz = u32(o + 16);
    for (let j = 0; j + 4 <= p_filesz; j += 4) {
      const fileOff = p_offset + j;
      if (fileOff + 4 > buf.length) break;
      const val = le ? buf.readUInt32LE(fileOff) : buf.readUInt32BE(fileOff);
      out[p_vaddr + j] = val;
    }
  }
}

process.stdout.write(JSON.stringify(out));

